import { useEffect, useState } from "react";
import { supabase } from "@/integrations/supabase/client";
import { downloadCSV, convertToCSV } from "@/lib/exportUtils";

const BATCH_SIZE = 1000;

const ExportNoCountry = () => {
  const [status, setStatus] = useState("正在加载数据...");
  const [done, setDone] = useState(false);

  useEffect(() => {
    const doExport = async () => {
      try {
        let allData: any[] = [];
        let offset = 0;
        let hasMore = true;

        while (hasMore) {
          setStatus(`正在加载数据... 已获取 ${allData.length} 条`);
          const { data, error } = await supabase
            .from("restaurants")
            .select("id, name, name_en, name_pt, type, type_en, address, city, district, country, lat, lng, template, store_level, visible, archived, created_at")
            .or("country.is.null,country.eq.")
            .order("name")
            .range(offset, offset + BATCH_SIZE - 1);

          if (error) throw error;
          if (!data || data.length === 0) {
            hasMore = false;
          } else {
            allData = [...allData, ...data];
            offset += BATCH_SIZE;
            if (data.length < BATCH_SIZE) hasMore = false;
          }
        }

        setStatus(`共 ${allData.length} 条，正在生成 CSV...`);

        // 根据地址推测国家
        const guessCountry = (address: string, lat: number, lng: number) => {
          if (!address && !lat) return "Unknown";
          const addr = (address || "").toLowerCase();
          if (addr.includes("portugal") || addr.includes("lisboa") || addr.includes("porto,")) return "Portugal?";
          if (addr.includes("spain") || addr.includes("españa")) return "Spain?";
          if (addr.includes("japan") || addr.includes("日本") || addr.includes("〒")) return "Japan?";
          if (addr.includes("china") || addr.includes("中国") || addr.includes("省") || addr.includes("市")) return "China?";
          if (addr.includes("korea") || addr.includes("한국")) return "South Korea?";
          if (addr.includes("france")) return "France?";
          if (addr.includes("germany") || addr.includes("deutschland")) return "Germany?";
          if (addr.includes("italy") || addr.includes("italia")) return "Italy?";
          if (addr.includes("uk") || addr.includes("united kingdom") || addr.includes("england") || addr.includes("london")) return "UK?";
          // 根据经纬度粗略判断
          if (lat && lng) {
            if (lat > 36 && lat < 42 && lng > -10 && lng < -6) return "Portugal?";
            if (lat > 36 && lat < 44 && lng > -10 && lng < 4) return "Spain?";
            if (lat > 30 && lat < 46 && lng > 128 && lng < 146) return "Japan?";
            if (lat > 18 && lat < 54 && lng > 73 && lng < 135) return "China?";
            if (lat > 33 && lat < 39 && lng > 124 && lng < 130) return "South Korea?";
            if (lat > 41 && lat < 51 && lng > -5 && lng < 10) return "France?";
            if (lat > 47 && lat < 55 && lng > 5 && lng < 16) return "Germany?";
            if (lat > 49 && lat < 61 && lng > -8 && lng < 2) return "UK?";
          }
          return "Unknown";
        };

        const headers = [
          "id", "name", "name_en", "type_en", "address", "city", "district",
          "guess_country", "lat", "lng", "template", "store_level", "visible", "archived", "created_at"
        ];

        const formatted = allData.map(r => ({
          id: r.id,
          name: r.name,
          name_en: r.name_en || "",
          type_en: Array.isArray(r.type_en) ? r.type_en.join(", ") : (r.type_en || ""),
          address: r.address || "",
          city: r.city || "",
          district: r.district || "",
          guess_country: guessCountry(r.address, r.lat, r.lng),
          lat: r.lat || "",
          lng: r.lng || "",
          template: r.template || "default",
          store_level: r.store_level || "",
          visible: r.visible ? "Yes" : "No",
          archived: r.archived ? "Yes" : "No",
          created_at: r.created_at ? new Date(r.created_at).toLocaleDateString() : "",
        }));

        const csv = convertToCSV(formatted, headers);
        const filename = `no_country_restaurants_${new Date().toISOString().split("T")[0]}.csv`;
        downloadCSV(csv, filename);

        setStatus(`✅ 导出完成！共 ${allData.length} 条记录，已下载 ${filename}`);
        setDone(true);
      } catch (err: any) {
        setStatus(`❌ 导出失败: ${err.message}`);
      }
    };

    doExport();
  }, []);

  return (
    <div className="min-h-screen flex items-center justify-center bg-background">
      <div className="text-center space-y-4 p-8">
        <h1 className="text-2xl font-bold">无国家数据导出</h1>
        <p className="text-lg text-muted-foreground">{status}</p>
        {done && (
          <p className="text-sm text-muted-foreground">
            CSV 包含 guess_country 列，根据地址和坐标自动推测国家，带 ? 后缀表示推测值
          </p>
        )}
      </div>
    </div>
  );
};

export default ExportNoCountry;
